  "verses": [
    {
      "n": 25,
      "column": "left",
      "text": "Tā nogahje Dahwids un\ntee Israēka Wezzajee/ un tee Ah-\nwersti/ ka tee ta KUNGA Der-\nribas Schkirstu no Obed-Eedo-\nma Namina ar Breeku augfcham\nwestu."
    },
    {
      "n": 26,
      "column": "left",
      "text": "Un kad Deewa teem Le-\nwiteein palihdseja/ kas ta KUN-\nGA Derribas Schkirstu nefse/\ntad uppureja tee feptinus Wehr-\nschus un feptinus Annus."
    },
    {
      "n": 27,
      "column": "left",
      "text": "Un Dahwids bji apgehr-\nbees arlinnu Swahrkeem/ un ta\npatt wiſſi Lewiti/ kas to Schkir-\nstu nefse/ un tee Dseedataji/ un\nKanantius to Dseedataju aug-\nstajs Usluhkotajs/ ir Dahwidam\nbija weens linnu Eewods Mug-\ngurā."
    },
    {
      "n": 28,
      "column": "left",
      "text": "Tā nefse wifs Israēls ta\nKUNGA Derribas Schkirstu\naugfcham ar Gawileschanu/ un\nBasinn Puhschanu/ un ar\nTrummetehtm/ un ar Pulksteni-\nscheem/ un spehleja ar Sohnia-\nStabulehm/ un Kohklehm."
    },
    {
      "n": 29,
      "column": "left",
      "text": "Un kad ta KUNGA Der-\nribas Schkirsts ithos Dahwida\nBillim nahze/ tad skattijahs Mi-\nkale Saula Meita zaur Lohgu\nahra/ un redseja to Kehnimu\nDahwidu detjam un spehlejam/\nun apfmeheje to fawa Sirdi.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ad tee nut to Deetwu\nSchkirstu atwedde/ tad\nwiꞥſch tee winnu pafcha\nTelti/ ko Dahwids tam bij us-\nzehlis/ un tee uppureja Dedsa-\nmo-Uppurus/ un Pateikfchanas-\nUppurus Deewa Preekscha."
    },
    {
      "n": 2,
      "column": "right",
      "text": "Un kad Dahwids tohs De-\ndsamo-Uppurus un Pateikfcha-\nnas-Uppurus bij pabeidsis/ tad\nfwehtija wiꞥſch tohs Laudis\neekſch ta KUNGA Wahrda."
    },
    {
      "n": 3,
      "column": "right",
      "text": "Un wiꞥſch isdallija itkat-\nram no Israēka/ tik labbi Wihr-\nram ka Seewai/ weenu Maisēs\nKlaipu/ un Galtas Gabbalu/ un\nweenu Wthna Stohpu."
    },
    {
      "n": 4,
      "column": "right",
      "text": "Un wiꞥſch lifke preekſch ta\nKUNGA Schkirstu zittus no\nteem Lewiteein par Sullaineen/\nka tee peeminnetu/ teiktu un fla-\nwetu to KUNgu Israēta Deewu."
    },
    {
      "n": 5,
      "column": "right",
      "text": "Affaws bija par Wirfneku/\nun wiꞥſch ohtre Sakarijus/ Jei-\nels/ Semiramots/ Jeiels un\nMatitijus/ un Elijabs/ un Be-\nnajus/ un Obed-Eedomg/ un Jei-\nels ar (spehlejameem) Rihkeem/\nSohma-Stabulehm/ un ar\nKohklehm/ un Affaws tikkahs ar\nPulkstenischeem dsirdetees."
    },
    {
      "n": 6,
      "column": "right",
      "text": "Un Benajus un Jeastēts\ntee Preesteri/ puhte weennuehr\nar Trummetehtm preekſch Dee-\nwa Derribas Schkirsta."
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tai Deena dewe Dah-\nwids pirnu Reisi fcho Dseedimu\nto KUNGU flaweht/ zaur Affa-\nwu un winna Brahteen."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Teizeet to KUNGII/ pee-\nJiiit fanzeet"
    }
  ],
  "confidence": "high",
  "notes": ""
}
